import React, { useState } from 'react';
import axios from 'axios';

const App = () => {
  const [code, setCode] = useState('');
  const [fileStructure, setFileStructure] = useState([]);
  const [loading, setLoading] = useState(false);

  const handleCodeChange = (e) => {
    setCode(e.target.value);
  };

  const handleGenerateFiles = () => {
    const lines = code.split('\n');

    const files = lines.map((line, index) => ({
      path: `file${index + 1}.js`,
      content: line,
    }));

    setFileStructure(files);
  };

  const handleDownloadZip = async () => {
    setLoading(true);

    try {
      const response = await axios.post(
        'http://localhost:5000/create-zip',
        {
          files: fileStructure,
        },
        {
          responseType: 'blob',
        }
      );

      const url = window.URL.createObjectURL(new Blob([response.data]));
      const link = document.createElement('a');

      link.href = url;
      link.setAttribute('download', 'project.zip');

      document.body.appendChild(link);
      link.click();

      setLoading(false);
    } catch (error) {
      console.error('Error downloading the zip file:', error);
      setLoading(false);
    }
  };

  return (
    <div className="max-w-xl mx-auto p-4">
      <h1 className="text-2xl font-bold mb-4">
        Code Analyzer & Zip Generator
      </h1>

      <textarea
        value={code}
        onChange={handleCodeChange}
        rows="10"
        className="w-full p-2 border border-gray-300 rounded mb-4"
        placeholder="Enter your code here..."
      />

      <button
        onClick={handleGenerateFiles}
        className="bg-blue-500 text-white p-2 rounded hover:bg-blue-600 mr-2"
      >
        Generate Files
      </button>

      <button
        onClick={handleDownloadZip}
        className="bg-green-500 text-white p-2 rounded hover:bg-green-600"
        disabled={loading}
      >
        {loading ? 'Generating...' : 'Download Zip'}
      </button>

      <div className="mt-4">
        <h2 className="text-xl font-semibold">Generated Files:</h2>

        <ul>
          {fileStructure.map((file, index) => (
            <li key={index}>{file.path}</li>
          ))}
        </ul>
      </div>
    </div>
  );
};

export default App;
